const item = $input.first().json;

const extraction = item.data && item.data.length > 0 ? item.data[0].company_data : (item.company_data || {});
const runId = item.run_id || '';
const domain = item.company_domain || '';

const context = {
  company_name: extraction.company_name || domain,
  description: extraction.company_description || '',
  domain: domain,
  run_id: runId,
  employees: extraction.employees || null,
  founded: extraction.founded || null,
  location: extraction.location || '',
  technology_stack: extraction.technology_stack || [],
  products: extraction.products || [],
  market_position: extraction.market_position || '',
  competitors: extraction.competitors || [],
  recent_news: extraction.recent_news || [],
  funding: extraction.funding || {},
  key_personnel: extraction.key_personnel || []
};

const companyStr = context.company_name;
const contextStr = JSON.stringify(context, null, 2);

const pillars = [
  { key: 'company_fit', label: 'Company Fit', weight: 0.10, desc: 'How well does this company align with our ideal customer profile? Consider industry, size, location, and product-market fit.' },
  { key: 'move_intent', label: 'Move Intent', weight: 0.35, desc: 'How strong is the signal that this company is actively looking to move or switch providers? Look for RFPs, contract end dates, pain points, expansion plans.' },
  { key: 'growth', label: 'Growth Signal', weight: 0.15, desc: 'What growth indicators exist? Hiring, fundraising, expansion, new product launches, market share increases.' },
  { key: 'financial', label: 'Financial Health', weight: 0.12, desc: 'Assess financial stability, funding, revenue trajectory, and ability to pay. Consider funding rounds, revenue range, employee growth.' },
  { key: 'decision_maker', label: 'Decision Maker Access', weight: 0.10, desc: 'How accessible are key decision makers? Do we have relationships, warm intros, or connections to executives?' },
  { key: 'network', label: 'Network Strength', weight: 0.08, desc: 'How strong is our existing network connection to this company? Shared investors, board connections, partner relationships.' },
  { key: 'opportunity', label: 'Opportunity Timing', weight: 0.05, desc: 'Is the timing right? Consider market events, recent changes, competitive landscape shifts, seasonal factors.' },
  { key: 'evidence', label: 'Evidence Quality', weight: 0.05, desc: 'How reliable and complete is the data we have on this company? Data freshness, source credibility, information density.' }
];

return [{
  json: {
    run_id: runId,
    company_domain: domain,
    company_name: context.company_name,
    context_summary: contextStr,
    pillars: pillars,
    source_extraction: extraction
  }
}];

