const items = $input.all();

const pillarWeights = {
  company_fit: 0.10,
  move_intent: 0.35,
  growth: 0.15,
  financial: 0.12,
  decision_maker: 0.10,
  network: 0.08,
  opportunity: 0.05,
  evidence: 0.05
};

const pillarLabels = {
  company_fit: 'Company Fit',
  move_intent: 'Move Intent',
  growth: 'Growth Signal',
  financial: 'Financial Health',
  decision_maker: 'Decision Maker Access',
  network: 'Network Strength',
  opportunity: 'Opportunity Timing',
  evidence: 'Evidence Quality'
};

const scores = {};
let compositeScore = 0;
let totalJustifications = [];

for (const item of items) {
  const json = item.json;
  const content = json.choices && json.choices[0] && json.choices[0].message && json.choices[0].message.content;
  if (!content) continue;

  try {
    const parsed = JSON.parse(content);
    const nodeName = json._node || '';
    const pillarKey = Object.keys(pillarLabels).find(k => nodeName.toLowerCase().includes(k.replace(/_/g, '')) || nodeName.includes(k)) || '';

    if (pillarKey) {
      scores[pillarKey] = {
        score: Math.round(Math.max(0, Math.min(100, parsed.score || 0))),
        weight: pillarWeights[pillarKey],
        justification: parsed.justification || '',
        evidence: parsed.evidence || ''
      };
      compositeScore += scores[pillarKey].score * pillarWeights[pillarKey];
      totalJustifications.push(`${pillarLabels[pillarKey]}: ${parsed.justification || ''}`);
    }
  } catch (e) {
    // skip failed parse
  }
}

compositeScore = Math.round(compositeScore);

return [{
  json: {
    run_id: items[0]?.json.run_id || '',
    company_domain: items[0]?.json.company_domain || '',
    company_name: items[0]?.json.company_name || '',
    composite_score: compositeScore,
    scores: scores,
    pillars: Object.entries(scores).map(([k, v]) => ({
      key: k,
      label: pillarLabels[k],
      score: v.score,
      weight: v.weight,
      weighted_score: Math.round(v.score * v.weight),
      justification: v.justification,
      evidence: v.evidence
    })),
    risk_factors: compositeScore < 50 ? ['Low overall score - review required'] : [],
    summary: `Overall score: ${compositeScore}/100. Top pillar: ${Object.entries(scores).sort((a, b) => b[1].score - a[1].score)[0]?.[0] || 'N/A'}.`
  }
}];

