const item = $input.first().json;

let reflection = {};
const content = item.choices && item.choices[0] && item.choices[0].message && item.choices[0].message.content;

if (content) {
  try {
    reflection = JSON.parse(content);
  } catch (e) {
    try {
      const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
      reflection = JSON.parse(cleaned);
    } catch (e2) {
      reflection = { reflection: 'Failed to parse', recommendation: 'Manual review needed' };
    }
  }
}

const scores = item.scores || {};
const pillars = item.pillars || [];

return [{
  json: {
    run_id: item.run_id || '',
    company_domain: item.company_domain || '',
    company_name: item.company_name || '',
    composite_score: item.composite_score || reflection.adjusted_score || 0,
    original_composite: item.composite_score || 0,
    adjusted_score: reflection.adjusted_score || item.composite_score || 0,
    reflection: reflection.reflection || '',
    recommendation: reflection.recommendation || '',
    key_risks: reflection.key_risks || [],
    next_steps: reflection.next_steps || [],
    scores: scores,
    pillars: pillars,
    risk_factors: item.risk_factors || []
  }
}];
